# Analysis of the voice call transcript for lead qualification based on BANT criteria
import json

# Key excerpts from the transcript showing BANT factors
transcript_analysis = {
    "lead_id": "00QWt0000089AekMAE",
    "lead_name": "Ali Hussein",
    "company": "Baghdad Tech Hub",
    "title": "Head of Emerging Technologies",
    "bant_factors": {
        "Budget": {
            "status": "MET",
            "evidence": "Budget of $2,261 is sufficient for 4 units at $2,000 total. Ali confirmed 'That fits really well.'"
        },
        "Authority": {
            "status": "NOT_MET", 
            "evidence": "Ali explicitly stated 'I'll need to consult with the finance team here since I don't have the final say.' - clear lack of decision-making authority."
        },
        "Need": {
            "status": "MET",
            "evidence": "Ali expressed clear need: 'We want to enhance our simulation capabilities, and the PulseSim Pro seems like a great fit.' Also showed interest in specific features."
        },
        "Timeline": {
            "status": "NOT_MET",
            "evidence": "While Ali mentioned 'tight timeline for installation', no specific decision/purchase timeframe was established. Timeline concern mentioned but not qualified."
        }
    }
}

# Determine which factors are responsible for failed qualification
failed_factors = [
    factor for factor, details in transcript_analysis["bant_factors"].items() 
    if details["status"] == "NOT_MET"
]

print("__RESULT__:")
print(json.dumps(failed_factors))

